"use client";
import { useCallback, useRef, useState } from "react";

export type VoiceGender = "female" | "male";
let globalVoiceGender: VoiceGender = "female";
let globalAutoSpeak = true;

export function useTTS() {
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [voiceGender, setVoiceGenderState] = useState<VoiceGender>(globalVoiceGender);
  const [autoSpeak, setAutoSpeakState] = useState(globalAutoSpeak);

  const setVoiceGender = useCallback((g: VoiceGender) => { globalVoiceGender = g; setVoiceGenderState(g); }, []);
  const setAutoSpeak = useCallback((v: boolean) => { globalAutoSpeak = v; setAutoSpeakState(v); }, []);

  const getVoice = useCallback((gender: VoiceGender): SpeechSynthesisVoice | null => {
    const voices = window.speechSynthesis.getVoices();
    if (!voices.length) return null;
    const femaleKw = ["female","woman","girl","zira","samantha","victoria","karen","moira","tessa","fiona","veena","susan","kate"];
    const maleKw = ["male","man","guy","david","mark","daniel","alex","fred","jorge","thomas","lee","rishi"];
    const kw = gender === "female" ? femaleKw : maleKw;
    const match = voices.find((v) => kw.some((k) => v.name.toLowerCase().includes(k)));
    if (match) return match;
    const en = voices.filter((v) => v.lang.startsWith("en"));
    if (!en.length) return voices[0];
    return gender === "female" ? en[0] : en[1] || en[0];
  }, []);

  const speak = useCallback((text: string) => {
    if (!("speechSynthesis" in window)) return;
    window.speechSynthesis.cancel();
    const clean = text.replace(/\*\*(.*?)\*\*/g, "$1").replace(/\*(.*?)\*/g, "$1").replace(/#{1,6}\s/g, "").replace(/[\u{1F300}-\u{1FAFF}]/gu, "").trim();
    if (!clean) return;
    const utt = new SpeechSynthesisUtterance(clean);
    const doSpeak = () => {
      const v = getVoice(globalVoiceGender);
      if (v) utt.voice = v;
      utt.rate = 0.92; utt.pitch = globalVoiceGender === "female" ? 1.1 : 0.85; utt.volume = 1;
      utt.onstart = () => setIsSpeaking(true);
      utt.onend = () => setIsSpeaking(false);
      utt.onerror = () => setIsSpeaking(false);
      window.speechSynthesis.speak(utt);
    };
    if (!window.speechSynthesis.getVoices().length) { window.speechSynthesis.onvoiceschanged = doSpeak; } else { doSpeak(); }
  }, [getVoice]);

  const stop = useCallback(() => { window.speechSynthesis.cancel(); setIsSpeaking(false); }, []);
  return { speak, stop, isSpeaking, voiceGender, setVoiceGender, autoSpeak, setAutoSpeak };
}
